public function exportHeader(): bool
{
    global $crlf;

    $data = $this->encode([
        'type' => 'header',
        'version' => Version::VERSION,
        'comment' => 'Export to JSON plugin for phpMyAdmin',
    ]);
    if ($data === false) {
        return false;
    }

    return $this->export->outputHandler('[' . $crlf . $data . ',' . $crlf);
}
